                "        self._x=x","        self._y=y","        self.state=state","        self.ps=ps","        self.rad=rad",
                "        #self.index=Sprite.index_no","        #Sprite.index_no+=1","        if on_map:",
                "            _db._gmap.append(self)","            _db._cmap[y//32][x//32][1].append(self)","","    def move(self):",
                "        pass","","    def sxy(self):","        return sxy(self._x,self._y)[:2]","","    def image(self):",
                "        return None","","    def neighbours(self):","        result=[]",
                "        for x,y in _db._cmap[self.y//32][self.x//32][0]:","            result+=_db._cmap[y][x][1]","        try:",
                "            result.remove(self)","        except:","            pass","        return result","",
                "    def remove_from_map(self):","        try:","            _db._gmap.remove(self)","        except:",
                "            pass","        try:","            _db._cmap[self.y//32][self.x//32][1].remove(self)","        except:",
                "            pass"," ","    @property","    def x(self):","        return self._x","","    @x.setter",
                "    def x(self,value):","        value &= _db.xmask","        if value//32!=self._x//32:","            try:",
                "                _db._cmap[self.y//32][self.x//32][1].remove(self)",
                "                _db._cmap[self.y//32][value//32][1].append(self)","            except:","                pass",
                "        self._x=value","","    @property","    def y(self):","        return self._y","","    @y.setter",
                "    def y(self,value):","        value &= _db.ymask","        if value//32!=self._y//32:","            try:",
                "                _db._cmap[self.y//32][self.x//32][1].remove(self)",
                "                _db._cmap[value//32][self.x//32][1].append(self)","            except:","                pass",
                "        self._y=value","","    def hits(self,dx,dy):","        result=[]","        dmx=_db.xmask+1",
                "        dmy=_db.ymask+1","        x=self.x+dx","        y=self.y+dy","        for neighbour in self.neighbours():",
